#!/usr/bin/env python3\n\nimport os\nimport sys\nimport django\nfrom datetime import datetime, timedelta\nfrom decimal import Decimal\n\n# Add the project directory to Python path\nsys.path.append('/path/to/orr')\nos.environ.setdefault('DJANGO_SETTINGS_MODULE', 'core.settings.development')\ndjango.setup()\n\nfrom django.contrib.auth.models import User\nfrom payment.models import Invoice, Subscription, PricingPlan\nfrom django.utils import timezone\n\ndef create_test_data():\n    print(\"Creating test payment and subscription data...\")\n    \n    # Create test users if they don't exist\n    users = []\n    for i in range(1, 6):\n        user, created = User.objects.get_or_create(\n            username=f'testuser{i}',\n            defaults={\n                'email': f'testuser{i}@example.com',\n                'first_name': f'Test',\n                'last_name': f'User{i}'\n            }\n        )\n        users.append(user)\n        if created:\n            print(f\"Created user: {user.username}\")\n    \n    # Create test pricing plans\n    plans = [\n        {'name': 'Basic Plan', 'amount': 2999, 'billing_type': 'monthly'},\n        {'name': 'Premium Plan', 'amount': 9999, 'billing_type': 'monthly'},\n        {'name': 'Enterprise Plan', 'amount': 19999, 'billing_type': 'monthly'},\n    ]\n    \n    created_plans = []\n    for plan_data in plans:\n        plan, created = PricingPlan.objects.get_or_create(\n            name=plan_data['name'],\n            defaults={\n                'stripe_price_id': f\"price_{plan_data['name'].lower().replace(' ', '_')}\",\n                'amount': plan_data['amount'],\n                'billing_type': plan_data['billing_type'],\n                'description': f\"Test {plan_data['name']}\"\n            }\n        )\n        created_plans.append(plan)\n        if created:\n            print(f\"Created plan: {plan.name}\")\n    \n    # Create test subscriptions\n    for i, user in enumerate(users):\n        plan = created_plans[i % len(created_plans)]\n        subscription, created = Subscription.objects.get_or_create(\n            user=user,\n            defaults={\n                'stripe_subscription_id': f'sub_test_{user.id}_{i}',\n                'stripe_customer_id': f'cus_test_{user.id}',\n                'plan': plan,\n                'plan_name': plan.name,\n                'is_active': i < 4,  # Make most active, one inactive\n                'current_period_end': timezone.now() + timedelta(days=30)\n            }\n        )\n        if created:\n            print(f\"Created subscription for {user.username}: {plan.name}\")\n    \n    # Create test invoices\n    statuses = ['Paid', 'Pending', 'Failed', 'Paid', 'Paid']\n    amounts = [29.99, 99.99, 199.99, 49.99, 79.99]\n    \n    for i, user in enumerate(users):\n        # Create multiple invoices per user\n        for j in range(3):\n            invoice_date = timezone.now().date() - timedelta(days=j*30)\n            invoice, created = Invoice.objects.get_or_create(\n                stripe_invoice_id=f'in_test_{user.id}_{i}_{j}',\n                defaults={\n                    'user': user,\n                    'billing_title': f'Billing #{user.id}{i}{j} – {invoice_date.strftime(\"%b %Y\")}',\n                    'status': statuses[i],\n                    'billing_date': invoice_date,\n                    'amount': Decimal(str(amounts[i])),\n                    'currency': 'USD',\n                    'plan': created_plans[i % len(created_plans)].name,\n                    'users': 1,\n                    'invoice_pdf': f'https://example.com/invoice_{user.id}_{j}.pdf',\n                    'hosted_invoice_url': f'https://example.com/hosted_invoice_{user.id}_{j}'\n                }\n            )\n            if created:\n                print(f\"Created invoice for {user.username}: ${invoice.amount}\")\n    \n    print(\"\\nTest data creation completed!\")\n    print(f\"Created {User.objects.count()} users\")\n    print(f\"Created {PricingPlan.objects.count()} pricing plans\")\n    print(f\"Created {Subscription.objects.count()} subscriptions\")\n    print(f\"Created {Invoice.objects.count()} invoices\")\n\nif __name__ == '__main__':\n    create_test_data()\n